#include<bits/stdc++.h>
using namespace std;
int main(){
    double ax,ay,bx,by,cx,cy,a,b,c,s,S;
    cin>>ax>>ay>>bx>>by>>cx>>cy;
    a=sqrt((ax-bx)*(ax-bx)+(by-ay)*(by-ay));
    b=sqrt((bx-cx)*(bx-cx)+(cy-by)*(cy-by));
    c=sqrt((cy-ay)*(cy-ay)+(ax-cx)*(ax-cx));
    s=(a+b+c)/2.0;
    S=sqrt(s*(s-a)*(s-b)*(s-c));
    cout<<S;
    return 0;
}
